3	import * as React from "react";
4	import * as AccordionPrimitive from "@radix-ui/react-accordion";
5	import { Slot } from "@radix-ui/react-slot";
6	import type { VariantProps } from "class-variance-authority";
7	import { cva } from "class-variance-authority";
8	import { ChevronDown, PanelLeftIcon } from "lucide-react";
9	
10	import { useIsMobile } from "@repo/ui/hooks/use-mobile";
11	import { cn } from "@repo/ui/lib/utils";
12	import { Button } from "@repo/ui/components/ui/button";
13	import { Input } from "@repo/ui/components/ui/input";
14	import { Separator } from "@repo/ui/components/ui/separator";
15	import {
16	  Sheet,
17	  SheetContent,
18	  SheetDescription,
19	  SheetHeader,
20	  SheetTitle,
21	} from "@repo/ui/components/ui/sheet";
22	import { Skeleton } from "@repo/ui/components/ui/skeleton";
