24	  Tooltip,
25	  TooltipContent,
26	  TooltipProvider,
27	  TooltipTrigger,
28	} from "@repo/ui/components/ui/tooltip";
29	
30	const SIDEBAR_COOKIE_NAME = "sidebar_state";
31	const SIDEBAR_COOKIE_MAX_AGE = 60 * 60 * 24 * 7;
32	const SIDEBAR_WIDTH = "14rem";
33	const SIDEBAR_WIDTH_MOBILE = "18rem";
34	const SIDEBAR_WIDTH_ICON = "2rem";
35	const SIDEBAR_WIDTH_HEADER_ONLY = "0rem";
36	const SIDEBAR_KEYBOARD_SHORTCUT = "b";
37	
38	interface SidebarContextProps {
39	  state: "expanded" | "collapsed";
40	  open: boolean;
41	  setOpen: (open: boolean) => void;
42	  openMobile: boolean;
43	  setOpenMobile: (open: boolean) => void;
44	  isMobile: boolean | undefined;
45	  toggleSidebar: () => void;
46	}
47	
48	const SidebarContext = React.createContext<SidebarContextProps | null>(null);
49	
50	function useSidebar() {
51	  const context = React.useContext(SidebarContext);
52	  if (!context) {
53	    throw new Error("useSidebar must be used within a SidebarProvider.");
54	  }
55	
56	  return context;
57	}
58	
59	function SidebarProvider({
60	  defaultOpen = true,
61	  open: openProp,
62	  onOpenChange: setOpenProp,
63	  className,
64	  style,
65	  children,
66	  ...props
67	}: React.ComponentProps<"div"> & {
68	  defaultOpen?: boolean;
69	  open?: boolean;
70	  onOpenChange?: (open: boolean) => void;
71	}) {
72	  const isMobile = useIsMobile();
73	  const [openMobile, setOpenMobile] = React.useState(false);
74	
75	  // This is the internal state of the sidebar.
76	  // We use openProp and setOpenProp for control from outside the component.
77	  const [_open, _setOpen] = React.useState(defaultOpen);
78	  const open = openProp ?? _open;
79	  const setOpen = React.useCallback(
80	    (value: boolean | ((value: boolean) => boolean)) => {
81	      const openState = typeof value === "function" ? value(open) : value;
82	      if (setOpenProp) {
83	        setOpenProp(openState);
84	      } else {
85	        _setOpen(openState);
86	      }
87	
88	      // This sets the cookie to keep the sidebar state.
89	      document.cookie = `${SIDEBAR_COOKIE_NAME}=${openState}; path=/; max-age=${SIDEBAR_COOKIE_MAX_AGE}`;
90	    },
91	    [setOpenProp, open],
92	  );
93	
94	  // Helper to toggle the sidebar.
95	  const toggleSidebar = React.useCallback(() => {
96	    return isMobile ? setOpenMobile((open) => !open) : setOpen((open) => !open);
97	  }, [isMobile, setOpen, setOpenMobile]);
98	
99	
100	  // We add a state so that we can do data-state="expanded" or "collapsed".
101	  // This makes it easier to style the sidebar with Tailwind classes.
102	  const state = open ? "expanded" : "collapsed";
103	
104	  const contextValue = React.useMemo<SidebarContextProps>(
105	    () => ({
106	      state,
107	      open,
108	      setOpen,
109	      isMobile,
110	      openMobile,
111	      setOpenMobile,
112	      toggleSidebar,
113	    }),
114	    [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar],
115	  );
116	
117	  return (
118	    <SidebarContext.Provider value={contextValue}>
119	      <TooltipProvider delayDuration={0}>
120	        <div
121	          data-slot="sidebar-wrapper"
122	          style={
123	            {
124	              "--sidebar-width": SIDEBAR_WIDTH,
125	              "--sidebar-width-icon": SIDEBAR_WIDTH_ICON,
126	              "--sidebar-width-header-only": SIDEBAR_WIDTH_HEADER_ONLY,
127	              ...style,
128	            } as React.CSSProperties
129	          }
130	          className={cn(
131	            "group/sidebar-wrapper has-data-[variant=inset]:bg-sidebar flex min-h-svh w-full",
132	            className,
133	          )}
134	          {...props}
135	        >
136	          {children}
137	        </div>
138	      </TooltipProvider>
139	    </SidebarContext.Provider>
140	  );
141	}
142	
143	function Sidebar({
144	  side = "left",
145	  variant = "sidebar",
146	  collapsible = "offcanvas",
147	  className,
148	  children,
149	  ...props
150	}: React.ComponentProps<"div"> & {
151	  side?: "left" | "right";
152	  variant?: "sidebar" | "floating" | "inset";
153	  collapsible?: "offcanvas" | "icon" | "header-only" | "none";
154	}) {
155	  const { isMobile, state, openMobile, setOpenMobile } = useSidebar();
156	
157	  if (collapsible === "none") {
158	    return (
159	      <div
160	        data-slot="sidebar"
161	        className={cn(
162	          "bg-sidebar text-sidebar-foreground flex h-full w-(--sidebar-width) flex-col",
163	          className,
164	        )}
165	        {...props}
166	      >
167	        {children}
168	      </div>
169	    );
170	  }
171	
172	  if (isMobile) {
173	    return (
174	      <Sheet open={openMobile} onOpenChange={setOpenMobile} {...props}>
175	        <SheetContent
176	          data-sidebar="sidebar"
177	          data-slot="sidebar"
178	          data-mobile="true"
179	          className="bg-sidebar text-sidebar-foreground w-(--sidebar-width) p-0 [&>button]:hidden"
180	          style={
181	            {
182	              "--sidebar-width": SIDEBAR_WIDTH_MOBILE,
183	            } as React.CSSProperties
184	          }
185	          side={side}
186	        >
187	          <SheetHeader className="sr-only">
188	            <SheetTitle>Sidebar</SheetTitle>
189	            <SheetDescription>Displays the mobile sidebar.</SheetDescription>
190	          </SheetHeader>
191	          <div className="flex h-full w-full flex-col">{children}</div>
192	        </SheetContent>
193	      </Sheet>
194	    );
195	  }
196	
197	  return (
198	    <div
199	      className="group peer text-sidebar-foreground hidden lg:block"
200	      data-state={state}
201	      data-collapsible={state === "collapsed" ? collapsible : ""}
202	      data-variant={variant}
203	      data-side={side}
204	      data-slot="sidebar"
205	    >
206	      {/* This is what handles the sidebar gap on desktop */}
207	      <div
208	        data-slot="sidebar-gap"
209	        className={cn(
