233	              : "group-data-[collapsible=icon]:w-(--sidebar-width-icon) group-data-[side=left]:border-r group-data-[side=right]:border-l",
234	          variant === "floating"
235	            ? "group-data-[collapsible=header-only]:w-[calc(var(--sidebar-width-header-only)+(--spacing(4))+2px)]"
236	            : variant === "inset"
237	              ? "group-data-[collapsible=header-only]:w-[calc(var(--sidebar-width-header-only)+(--spacing(4))+2px)]"
238	              : "group-data-[collapsible=header-only]:w-(--sidebar-width-header-only) group-data-[side=left]:border-r group-data-[side=right]:border-l",
239	          className,
240	        )}
241	        {...props}
242	      >
243	        <div
244	          data-sidebar="sidebar"
245	          data-slot="sidebar-inner"
246	          className="bg-sidebar group-data-[variant=floating]:border-sidebar-border flex h-full w-full flex-col group-data-[variant=floating]:rounded-lg group-data-[variant=floating]:border group-data-[variant=floating]:shadow-sm"
247	        >
248	          {children}
249	        </div>
250	      </div>
251	    </div>
252	  );
253	}
